const { S3Client, GetObjectCommand, PutObjectCommand } = require('@aws-sdk/client-s3');

const s3Client = new S3Client();

const ALLOWED_BUCKET = process.env.SOURCE_BUCKET;
const DESTINATION_BUCKET = process.env.DESTINATION_BUCKET;
const MAX_FILE_SIZE = parseInt(process.env.MAX_FILE_SIZE || '104857600', 10); // 100MB default
const ALLOWED_EXTENSIONS = ['.txt', '.csv', '.json', '.xml', '.pdf', '.doc', '.docx'];

exports.handler = async (event) => {
    const results = [];

    for (const record of event.Records) {
        try {
            const sourceBucket = record.s3.bucket.name;
            const rawKey = record.s3.object.key;
            const fileSize = record.s3.object.size;

            // Validate source bucket matches expected bucket
            if (ALLOWED_BUCKET && sourceBucket !== ALLOWED_BUCKET) {
                console.error(`Unauthorized bucket: ${sourceBucket}`);
                results.push({ key: rawKey, status: 'error', message: 'Unauthorized source bucket' });
                continue;
            }

            // Decode the S3 key (S3 events URL-encode the key)
            const sourceKey = decodeURIComponent(rawKey.replace(/\+/g, ' '));

            // Validate and sanitize the key to prevent path traversal
            const sanitizedKey = sanitizeS3Key(sourceKey);
            if (!sanitizedKey) {
                console.error(`Invalid S3 key rejected: ${sourceKey}`);
                results.push({ key: sourceKey, status: 'error', message: 'Invalid file key' });
                continue;
            }

            // Validate file extension
            const extension = getFileExtension(sanitizedKey).toLowerCase();
            if (!ALLOWED_EXTENSIONS.includes(extension)) {
                console.error(`Disallowed file extension: ${extension}`);
                results.push({ key: sanitizedKey, status: 'error', message: 'File type not allowed' });
                continue;
            }

            // Validate file size from event metadata
            if (fileSize && fileSize > MAX_FILE_SIZE) {
                console.error(`File too large: ${fileSize} bytes`);
                results.push({ key: sanitizedKey, status: 'error', message: 'File exceeds size limit' });
                continue;
            }

            // Read the file from S3
            const fileContent = await getFileFromS3(sourceBucket, sanitizedKey);

            if (!fileContent) {
                results.push({ key: sanitizedKey, status: 'error', message: 'Failed to read file' });
                continue;
            }

            // Process the file content
            const processedContent = await processFile(fileContent, sanitizedKey);

            // Build the output key using sanitized filename
            const outputKey = buildOutputKey(sanitizedKey);

            // Validate destination bucket is different from source to prevent loops
            const destBucket = DESTINATION_BUCKET || `${sourceBucket}-processed`;
            if (destBucket === sourceBucket) {
                // If same bucket, ensure output prefix differs from input to prevent infinite loops
                const sourcePrefix = sanitizedKey.split('/')[0];
                const outputPrefix = outputKey.split('/')[0];
                if (sourcePrefix === outputPrefix) {
                    console.error('Output path would trigger recursive invocation');
                    results.push({ key: sanitizedKey, status: 'error', message: 'Recursive trigger detected' });
                    continue;
                }
            }

            // Save processed content to destination
            await saveFileToS3(destBucket, outputKey, processedContent);

            console.log(`Successfully processed: ${sanitizedKey} -> ${outputKey}`);
            results.push({ key: sanitizedKey, outputKey, status: 'success' });

        } catch (error) {
            // Log error without leaking sensitive details in response
            console.error(`Error processing record: ${error.message}`, {
                errorName: error.name,
                requestId: event.Records?.[0]?.responseElements?.['x-amz-request-id']
            });
            results.push({
                key: record.s3?.object?.key || 'unknown',
                status: 'error',
                message: 'Internal processing error'
            });
        }
    }

    return {
        statusCode: 200,
        body: {
            processedCount: results.filter(r => r.status === 'success').length,
            errorCount: results.filter(r => r.status === 'error').length,
            results
        }
    };
};

/**
 * Sanitize S3 key to prevent path traversal and injection attacks.
 */
function sanitizeS3Key(key) {
    if (!key || typeof key !== 'string') {
        return null;
    }

    // Reject keys with null bytes
    if (key.includes('\0')) {
        return null;
    }

    // Normalize the path and reject path traversal attempts
    const normalized = key.split('/').filter(segment => {
        // Reject '..' segments (path traversal)
        if (segment === '..') return false;
        // Reject empty segments that could indicate '//' manipulation
        // (but allow leading/trailing which S3 supports)
        return true;
    }).join('/');

    // Reject if normalization changed the path in a suspicious way
    if (normalized.includes('..')) {
        return null;
    }

    // Reject excessively long keys (S3 max is 1024 bytes)
    if (Buffer.byteLength(normalized, 'utf-8') > 1024) {
        return null;
    }

    // Reject keys that start with '/' (absolute path attempt)
    if (normalized.startsWith('/')) {
        return null;
    }

    return normalized;
}

/**
 * Extract file extension safely.
 */
function getFileExtension(filename) {
    const basename = filename.split('/').pop() || '';
    const dotIndex = basename.lastIndexOf('.');
    if (dotIndex === -1 || dotIndex === 0) {
        return '';
    }
    return basename.substring(dotIndex);
}

/**
 * Read file from S3 with size validation.
 */
async function getFileFromS3(bucket, key) {
    const command = new GetObjectCommand({
        Bucket: bucket,
        Key: key
    });

    const response = await s3Client.send(command);

    // Double-check content length from S3 response
    if (response.ContentLength && response.ContentLength > MAX_FILE_SIZE) {
        throw new Error(`File size ${response.ContentLength} exceeds maximum allowed size`);
    }

    // Read the stream with size limiting
    const chunks = [];
    let totalSize = 0;

    for await (const chunk of response.Body) {
        totalSize += chunk.length;
        if (totalSize > MAX_FILE_SIZE) {
            // Destroy the stream to stop downloading
            if (response.Body.destroy) {
                response.Body.destroy();
            }
            throw new Error('File size exceeded limit during download');
        }
        chunks.push(chunk);
    }

    return Buffer.concat(chunks);
}

/**
 * Process the file content.
 * Replace this with actual document processing logic.
 */
async function processFile(fileContent, filename) {
    const extension = getFileExtension(filename).toLowerCase();
    const contentString = fileContent.toString('utf-8');

    let processed;

    switch (extension) {
        case '.json':
            processed = processJsonFile(contentString);
            break;
        case '.csv':
            processed = processCsvFile(contentString);
            break;
        case '.txt':
            processed = processTextFile(contentString);
            break;
        case '.xml':
            processed = processXmlFile(contentString);
            break;
        default:
            // For binary formats like PDF/DOC, return metadata wrapper
            processed = JSON.stringify({
                processedAt: new Date().toISOString(),
                originalFile: filename.split('/').pop(),
                fileSize: fileContent.length,
                status: 'binary_file_received',
                message: 'Binary file stored for further processing'
            }, null, 2);
            break;
    }

    return Buffer.from(processed, 'utf-8');
}

function processJsonFile(content) {
    // Parse with safety - limit nesting depth isn't built-in,
    // but we validate size already
    const data = JSON.parse(content);

    const result = {
        processedAt: new Date().toISOString(),
        originalRecordCount: Array.isArray(data) ? data.length : 1,
        data: data,
        metadata: {
            pipeline: 'document-processing',
            version: '1.0'
        }
    };

    return JSON.stringify(result, null, 2);
}

function processCsvFile(content) {
    const lines = content.split('\n').filter(line => line.trim().length > 0);
    const header = lines[0] || '';
    const dataLines = lines.slice(1);

    const result = {
        processedAt: new Date().toISOString(),
        columns: header.split(',').map(col => col.trim()),
        rowCount: dataLines.length,
        preview: dataLines.slice(0, 5),
        metadata: {
            pipeline: 'document-processing',
            version: '1.0'
        }
    };

    return JSON.stringify(result, null, 2);
}

function processTextFile(content) {
    const lines = content.split('\n');
    const wordCount = content.split(/\s+/).filter(w => w.length > 0).length;

    const result = {
        processedAt: new Date().toISOString(),
        lineCount: lines.length,
        wordCount: wordCount,
        characterCount: content.length,
        preview: content.substring(0, 500),
        metadata: {
            pipeline: 'document-processing',
            version: '1.0'
        }
    };

    return JSON.stringify(result, null, 2);
}

function processXmlFile(content) {
    // Basic XML processing - extract structure info without full parsing
    // to avoid XML External Entity (XXE) attacks
    // Do NOT use xml2js or similar without disabling external entities

    // Strip any DOCTYPE declarations to prevent XXE
    const sanitizedContent = content.replace(/<!DOCTYPE[^>]*>/gi, '');

    const tagMatches = sanitizedContent.match(/<(\w+)[^>]*>/g) || [];
    const uniqueTags = [...new Set(tagMatches.map(t => {
        const match = t.match(/<(\w+)/);
        return match ? match[1] : null;
    }).filter(Boolean))];

    const result = {
        processedAt: new Date().toISOString(),
        tagCount: tagMatches.length,
        uniqueTags: uniqueTags,
        contentLength: content.length,
        metadata: {
            pipeline: 'document-processing',
            version: '1.0',
            note: 'XML processed with XXE prevention'
        }
    };

    return JSON.stringify(result, null, 2);
}

/**
 * Build the output key from the original filename.
 */
function buildOutputKey(sourceKey) {
    const filename = sourceKey.split('/').pop();
    const nameWithoutExt = filename.substring(0, filename.lastIndexOf('.')) || filename;
    const timestamp = Date.now();

    // Place processed files under a 'processed/' prefix
    return `processed/${nameWithoutExt}-processed-${timestamp}.json`;
}

/**
 * Save processed file to S3 with server-side encryption.
 */
async function saveFileToS3(bucket, key, content) {
    const command = new PutObjectCommand({
        Bucket: bucket,
        Key: key,
        Body: content,
        ContentType: 'application/json',
        ServerSideEncryption: 'aws:kms',
        // Prevent public access at object level
        ACL: undefined // Do not set any ACL; rely on bucket policy
    });

    await s3Client.send(command);
}